import React, { useState, useEffect } from "react";
import Hero from "../components/Hero";
import TourCard from "../components/TourCard";
import Contact from "../components/Contact";
import { getTours } from "../services/api";

const CATEGORIES = ["All", "Sacred Circuit", "Alpine Adventure"];

const AboutSection = () => (
  <section id="about" className="py-24 bg-white">
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      <div className="grid lg:grid-cols-2 gap-16 items-center">
        <div>
          <span className="text-mountain-900 text-xs font-semibold uppercase tracking-widest">
            About Us
          </span>
          <h2 className="font-display text-4xl font-bold text-gray-900 mt-3 mb-6 leading-tight">
            Born in the Foothills,
            <br />
            Called to the Peaks
          </h2>
          <p className="text-gray-600 leading-relaxed mb-4">
            Kumaon Soul Travels was founded by passionate trekkers from Haldwani
            who grew up in the shadow of the Himalayas. We specialise
            exclusively in the Kumaon region — a part of Uttarakhand that
            remains unspoiled, deeply spiritual, and stunningly beautiful.
          </p>
          <p className="text-gray-600 leading-relaxed mb-8">
            Every trek we design is personally scouted by our team. We work with
            local guides, village homestays, and porters, ensuring your journey
            is authentic, safe, and directly benefits the mountain communities
            you visit.
          </p>
          <div className="grid grid-cols-3 gap-6">
            {[
              { number: "500+", label: "Treks Completed" },
              { number: "8+", label: "Years Experience" },
              { number: "100%", label: "Safe Returns" },
            ].map((s) => (
              <div key={s.label} className="text-center">
                <div className="font-display text-3xl font-bold text-mountain-900">
                  {s.number}
                </div>
                <div className="text-xs text-gray-500 mt-1">{s.label}</div>
              </div>
            ))}
          </div>
        </div>
        <div className="relative">
          <img
            src="https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?w=700&q=85"
            alt="Himalayan landscape"
            className="rounded-2xl w-full h-96 object-cover shadow-xl"
          />
          <div className="absolute -bottom-6 -left-6 bg-mountain-900 text-white rounded-2xl p-5 shadow-xl">
            <p className="font-display font-semibold text-lg">
              Starting from Haldwani
            </p>
            <p className="text-blue-200 text-sm mt-1">Uttarakhand, India</p>
          </div>
        </div>
      </div>
    </div>
  </section>
);

const Home = () => {
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeCategory, setActiveCategory] = useState("All");
  const [error, setError] = useState("");

  useEffect(() => {
    getTours()
      .then((res) => setTours(res.data.data))
      .catch(() =>
        setError(
          "Could not load tours. Please ensure the backend server is running.",
        ),
      )
      .finally(() => setLoading(false));
  }, []);

  const filtered =
    activeCategory === "All"
      ? tours
      : tours.filter((t) => t.category === activeCategory);
  const sacred = filtered.filter((t) => t.category === "Sacred Circuit");
  const alpine = filtered.filter((t) => t.category === "Alpine Adventure");

  return (
    <>
      <Hero />
      <AboutSection />

      {/* Tours Section */}
      <section id="tours" className="py-24 bg-gray-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-12">
            <span className="text-mountain-900 text-xs font-semibold uppercase tracking-widest">
              Our Packages
            </span>
            <h2 className="font-display text-4xl font-bold text-gray-900 mt-3 mb-4">
              Himalayan Trek Packages
            </h2>
            <p className="text-gray-500 max-w-2xl mx-auto">
              All treks depart from Haldwani. Choose your adventure — a sacred
              pilgrimage circuit or a high-altitude alpine challenge.
            </p>

            {/* Filter tabs */}
            <div className="flex items-center justify-center gap-2 mt-8 flex-wrap">
              {CATEGORIES.map((cat) => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`px-5 py-2.5 rounded-full text-sm font-medium transition-all duration-200 ${
                    activeCategory === cat
                      ? "bg-mountain-900 text-white shadow-md"
                      : "bg-white text-gray-600 border border-gray-200 hover:border-mountain-900 hover:text-mountain-900"
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          {loading && (
            <div className="flex justify-center py-20">
              <div className="w-10 h-10 border-4 border-mountain-900/20 border-t-mountain-900 rounded-full animate-spin" />
            </div>
          )}

          {error && (
            <div className="text-center py-16">
              <p className="text-red-500 font-medium">{error}</p>
              <p className="text-gray-400 text-sm mt-2">
                Run{" "}
                <code className="bg-gray-100 px-2 py-0.5 rounded">
                  npm run dev
                </code>{" "}
                in the backend folder.
              </p>
            </div>
          )}

          {!loading && !error && (
            <>
              {(activeCategory === "All" ||
                activeCategory === "Sacred Circuit") &&
                sacred.length > 0 && (
                  <div className="mb-16">
                    <div className="flex items-center gap-3 mb-8">
                      <div className="w-1 h-8 bg-mountain-900 rounded-full" />
                      <div>
                        <h3 className="font-display text-2xl font-bold text-gray-900">
                          The Sacred Circuit
                        </h3>
                        <p className="text-gray-500 text-sm">
                          Pilgrimages — Adi Kailash · Om Parvat · Darma Valley
                        </p>
                      </div>
                    </div>
                    <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                      {sacred.map((tour) => (
                        <TourCard key={tour._id} tour={tour} />
                      ))}
                    </div>
                  </div>
                )}

              {(activeCategory === "All" ||
                activeCategory === "Alpine Adventure") &&
                alpine.length > 0 && (
                  <div>
                    <div className="flex items-center gap-3 mb-8">
                      <div className="w-1 h-8 bg-forest-700 rounded-full" />
                      <div>
                        <h3 className="font-display text-2xl font-bold text-gray-900">
                          The Alpine Adventure
                        </h3>
                        <p className="text-gray-500 text-sm">
                          High-altitude treks — Munsyari · Milam Glacier ·
                          Khaliya Top
                        </p>
                      </div>
                    </div>
                    <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                      {alpine.map((tour) => (
                        <TourCard key={tour._id} tour={tour} />
                      ))}
                    </div>
                  </div>
                )}

              {filtered.length === 0 && (
                <p className="text-center text-gray-400 py-16">
                  No tours found in this category.
                </p>
              )}
            </>
          )}
        </div>
      </section>

      <Contact />
    </>
  );
};

export default Home;
